import org.junit.jupiter.api.Test;

public class ParseBenchmarkTest {

  private static File testZipFile;

  @BeforeAll
  static void createTestZip() throws Exception {
    // Create a temporary zip file with a known entry
    testZipFile = File.createTempFile("ParseBenchmarkData", ".zip");
    try (ZipOutputStream zos = new ZipOutputStream(new FileOutputStream(testZipFile))) {
      ZipEntry entry = new ZipEntry("testfile.txt");
      zos.putNextEntry(entry);
      String content = "Hello, world!";
      zos.write(content.getBytes(StandardCharsets.UTF_8));
      zos.closeEntry();
    }
  }

  @AfterAll
  static void cleanup() {
    if (testZipFile != null && testZipFile.exists()) {
      testZipFile.delete();
    }
  }

  /**
   * Use reflection to invoke the private static method 'resourceToString' of ParseBenchmark,
   * but temporarily override the private static method 'getResourceFile' to return our test zip file.
   */
  private static String invokeResourceToString(String fileName) throws Exception {
    // Get the resourceToString method
    Method resourceToStringMethod = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
    resourceToStringMethod.setAccessible(true);

    // Create a dynamic proxy for getResourceFile by using a subclass with reflection to replace the method
    // Since we can't override private static methods, we use a trick:
    // We create a new File object pointing to our testZipFile and temporarily replace the resource file on classpath

    // Instead of invoking getResourceFile, we invoke resourceToString but patch getResourceFile via reflection
    // We'll do this by temporarily replacing the returned File from getResourceFile by patching the method via reflection

    // To do this, we first get the getResourceFile method
    Method getResourceFileMethod = ParseBenchmark.class.getDeclaredMethod("getResourceFile", String.class);
    getResourceFileMethod.setAccessible(true);

    // We cannot replace the method, so we simulate by replacing the resource file on disk

    // Get the original file returned by getResourceFile
    File originalFile = null;
    try {
      originalFile = (File) getResourceFileMethod.invoke(null, "/ParseBenchmarkData.zip");
    } catch (InvocationTargetException e) {
      // If getResourceFile throws, fallback to null
      originalFile = null;
    }

    File backupFile = null;
    if (originalFile != null && originalFile.exists()) {
      backupFile = new File(originalFile.getAbsolutePath() + ".bak");
      if (!originalFile.renameTo(backupFile)) {
        throw new IllegalStateException("Cannot backup original resource file");
      }
    }

    if (originalFile != null) {
      Files.copy(testZipFile.toPath(), originalFile.toPath(), java.nio.file.StandardCopyOption.REPLACE_EXISTING);
    }

    try {
      return (String) resourceToStringMethod.invoke(null, fileName);
    } catch (InvocationTargetException e) {
      throw (e.getCause() != null) ? (Exception) e.getCause() : e;
    } finally {
      if (backupFile != null && backupFile.exists()) {
        if (!backupFile.renameTo(originalFile)) {
          throw new IllegalStateException("Cannot restore original resource file");
        }
      }
    }
  }

  @Test
  void testResourceToString_readsContentCorrectly() throws Exception {
    String content = invokeResourceToString("testfile.txt");
    assertEquals("Hello, world!", content);
  }

  @Test
  void testResourceToString_fileNotFound_throwsException() throws Exception {
    Exception ex = assertThrows(IllegalArgumentException.class, () -> {
      invokeResourceToString("nonexistent.txt");
    });
    assertEquals("File not found in zip: nonexistent.txt", ex.getMessage());
  }

  @Test
  void testResourceToString_nullFileName_throwsNullPointerException() throws Exception {
    Exception ex = assertThrows(NullPointerException.class, () -> {
      invokeResourceToString(null);
    });
    // No need to check message, just ensure NPE is thrown
  }
}
